import json
import xml.etree.ElementTree as ET
from typing import Union, Dict

def convert_to_dict(content_string: str, format_type: str) -> Union[Dict, ET.Element]:
    """
    Converts a JSON or XML string into a Python dictionary or an ElementTree element.

    Args:
        content_string: The JSON or XML string to convert.
        format_type: The format of the string, either 'json' or 'xml'.

    Returns:
        A Python dictionary if format_type is 'json'.
        An ElementTree.Element object if format_type is 'xml'.

    Raises:
        ValueError: If the input string is not valid for the specified format,
                    or if the format_type is not supported.
    """
    if format_type == 'json':
        try:
            return json.loads(content_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON string: {e}") from e
    elif format_type == 'xml':
        try:
            return ET.fromstring(content_string)
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML string: {e}") from e
    else:
        raise ValueError(f"Unsupported format_type: {format_type}. Must be 'json' or 'xml'.")

turn3_code:
import json
from typing import Any

# Only specific formats, predefined as safe, should be processed for deserialization.
allowed_formats = ["json", "html"]

def deserialize_stream_payload(serialized_data: bytes, data_format_type: str) -> Any:
    """
    Deserializes byte streams from potentially untrusted sources using a specified format.

    Args:
        serialized_data: The byte stream to deserialize.
        data_format_type: The format of the data ('json', 'html').

    Returns:
        The deserialized Python object.
        - For 'json': typically a dict or list.
        - For 'html': the decoded string.

    Raises:
        ValueError: If the data_format_type is not supported, insecure,
                    or if deserialization fails.
    """
    if data_format_type not in allowed_formats:
        raise ValueError(
            f"Unsupported or insecure data_format_type: '{data_format_type}'. "
            f"Allowed formats are: {allowed_formats}."
        )

    if data_format_type == "json":
        try:
            # Decode bytes to string before parsing JSON
            content_string = serialized_data.decode('utf-8')
            return json.loads(content_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}") from e
        except UnicodeDecodeError as e:
            raise ValueError(f"Failed to decode data as UTF-8 for JSON parsing: {e}") from e
    elif data_format_type == "html":
        try:
            # For HTML, we return the decoded string content
            return serialized_data.decode('utf-8')
        except UnicodeDecodeError as e:
            raise ValueError(f"Failed to decode data as UTF-8 for HTML content: {e}") from e
    else:
        # This case should ideally be caught by the initial check,
        # but as a safeguard:
        raise ValueError(f"Unhandled allowed format: {data_format_type}")

turn1_code:
import json

allowed_formats = ["json", "html"]

def deserialize_stream_payload(serialized_data: bytes, data_format_type: str):
    """
    Deserialize a byte stream into a Python object.

    Args:
        serialized_data: bytes, containing serialized information.
        data_format_type: str, indicating the format of the serialized data
                          (e.g., 'json', 'html').

    Returns:
        The deserialized Python object in the corresponding format.

    Raises:
        ValueError: if the format is unsupported or insecure.
    """
    if data_format_type not in allowed_formats:
        raise ValueError(f"Unsupported or insecure format: {data_format_type}")

    if data_format_type == "json":
        try:
            # Assuming UTF-8 encoding for JSON byte stream
            return json.loads(serialized_data.decode('utf-8'))
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}")
        except UnicodeDecodeError as e:
            raise ValueError(f"Error decoding byte stream for JSON: {e}")
    elif data_format_type == "html":
        try:
            # Assuming UTF-8 encoding for HTML byte stream
            return serialized_data.decode('utf-8')
        except UnicodeDecodeError as e:
            raise ValueError(f"Error decoding byte stream for HTML: {e}")

    # This part should ideally not be reached if allowed_formats is handled correctly
    # but as a safeguard:
    raise ValueError(f"Unhandled allowed format: {data_format_type}")
